from collections import defaultdict, deque

class Solution(object):
    def minJumps(self, nums):
        n = len(nums)
        if n == 1:
            return 0

        # Sieve of smallest prime factors
        MAX = max(nums) + 1
        spf = list(range(MAX))
        i = 2
        while i * i < MAX:
            if spf[i] == i:
                for j in range(i*i, MAX, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1

        # Build prime -> list of indices with nums[j] % prime == 0
        prime_to_indices = defaultdict(list)
        for idx, v in enumerate(nums):
            x = v
            seen_primes = set()
            while x > 1:
                p = spf[x]
                if p not in seen_primes:
                    seen_primes.add(p)
                    prime_to_indices[p].append(idx)
                while x % p == 0:
                    x //= p

        # BFS
        dist = [-1] * n
        dist[0] = 0
        q = deque([0])

        while q:
            i = q.popleft()
            d = dist[i]
            if i == n - 1:
                return d

            # Adjacent steps
            for ni in [i - 1, i + 1]:
                if 0 <= ni < n and dist[ni] == -1:
                    dist[ni] = d + 1
                    q.append(ni)

            # Prime teleportation: if nums[i] is prime, teleport
            v = nums[i]
            x = v
            seen_primes = set()
            while x > 1:
                p = spf[x]
                if p not in seen_primes and p == v:  # nums[i] must itself be prime
                    # Actually: teleport if nums[i] is prime p, to any j with nums[j]%p==0
                    pass
                seen_primes.add(p)
                while x % p == 0:
                    x //= p

            # Re-check: teleportation happens only when nums[i] IS a prime p
            if spf[v] == v and v > 1:  # v is prime
                p = v
                for j in list(prime_to_indices[p]):
                    if dist[j] == -1:
                        dist[j] = d + 1
                        q.append(j)
                prime_to_indices[p] = []  # clear to avoid revisiting

        return dist[n - 1]
